// SPDX-License-Identifier: MIT
pragma solidity 0.8.3;
// Adopted from https://github.com/lazyledger/protobuf3-solidity-lib/blob/master/contracts/ProtobufLib.sol
library ProtobufLib {
    /// @notice Protobuf wire types.
    enum WireType {
        Varint,
        Bits64,
        LengthDelimited,
        StartGroup,
        EndGroup,
        Bits32,
        WIRE_TYPE_MAX
    }

    /// @dev Maximum number of bytes for a varint.
    /// @dev 64 bits, in groups of base-128 (7 bits).
    uint64 internal constant MAX_VARINT_BYTES = 10;

    ////////////////////////////////////
    // Decoding
    ////////////////////////////////////

    /// @notice Decode key.
    /// @dev https://developers.google.com/protocol-buffers/docs/encoding#structure
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Field number
    /// @return Wire type
    function decode_key(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint64,
            WireType
        )
    {
        // The key is a varint with encoding
        // (field_number << 3) | wire_type
        (bool success, uint64 pos, uint64 key) = decode_varint(p, buf);
        if (!success) {
            return (false, pos, 0, WireType.WIRE_TYPE_MAX);
        }

        uint64 field_number = key >> 3;
        uint64 wire_type_val = key & 0x07;
        // Check that wire type is bounded
        if (wire_type_val >= uint64(WireType.WIRE_TYPE_MAX)) {
            return (false, pos, 0, WireType.WIRE_TYPE_MAX);
        }
        WireType wire_type = WireType(wire_type_val);

        // Start and end group types are deprecated, so forbid them
        if (
            wire_type == WireType.StartGroup || wire_type == WireType.EndGroup
        ) {
            return (false, pos, 0, WireType.WIRE_TYPE_MAX);
        }

        return (true, pos, field_number, wire_type);
    }

    /// @notice Decode varint.
    /// @dev https://developers.google.com/protocol-buffers/docs/encoding#varints
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_varint(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint64
        )
    {
        uint64 val;
        uint64 i;

        for (i = 0; i < MAX_VARINT_BYTES; i++) {
            // Check that index is within bounds
            if (i + p >= buf.length) {
                return (false, p, 0);
            }

            // Get byte at offset
            uint8 b = uint8(buf[p + i]);

            // Highest bit is used to indicate if there are more bytes to come
            // Mask to get 7-bit value: 0111 1111
            uint8 v = b & 0x7F;

            // Groups of 7 bits are ordered least significant first
            val |= uint64(v) << uint64(i * 7);

            // Mask to get keep going bit: 1000 0000
            if (b & 0x80 == 0) {
                // [STRICT]
                // Check for trailing zeroes if more than one byte is used
                // (the value 0 still uses one byte)
                if (i > 0 && v == 0) {
                    return (false, p, 0);
                }

                break;
            }
        }

        // Check that at most MAX_VARINT_BYTES are used
        if (i >= MAX_VARINT_BYTES) {
            return (false, p, 0);
        }

        // [STRICT]
        // If all 10 bytes are used, the last byte (most significant 7 bits)
        // must be at most 0000 0001, since 7*9 = 63
        if (i == MAX_VARINT_BYTES - 1) {
            if (uint8(buf[p + i]) > 1) {
                return (false, p, 0);
            }
        }

        return (true, p + i + 1, val);
    }

    /// @notice Decode varint int32.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_int32(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            int32
        )
    {
        (bool success, uint64 pos, uint64 val) = decode_varint(p, buf);
        if (!success) {
            return (false, pos, 0);
        }

        // [STRICT]
        // Highest 4 bytes must be 0 if positive
        if (val >> 63 == 0) {
            if (val & 0xFFFFFFFF00000000 != 0) {
                return (false, pos, 0);
            }
        }

        return (true, pos, int32(uint32(val)));
    }

    /// @notice Decode varint int64.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_int64(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            int64
        )
    {
        (bool success, uint64 pos, uint64 val) = decode_varint(p, buf);
        if (!success) {
            return (false, pos, 0);
        }

        return (true, pos, int64(val));
    }

    /// @notice Decode varint uint32.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_uint32(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint32
        )
    {
        (bool success, uint64 pos, uint64 val) = decode_varint(p, buf);
        if (!success) {
            return (false, pos, 0);
        }

        // [STRICT]
        // Highest 4 bytes must be 0
        if (val & 0xFFFFFFFF00000000 != 0) {
            return (false, pos, 0);
        }

        return (true, pos, uint32(val));
    }

    /// @notice Decode varint uint64.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_uint64(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint64
        )
    {
        (bool success, uint64 pos, uint64 val) = decode_varint(p, buf);
        if (!success) {
            return (false, pos, 0);
        }

        return (true, pos, val);
    }

    // /// @notice Decode varint sint32.
    // /// @param p Position
    // /// @param buf Buffer
    // /// @return Success
    // /// @return New position
    // /// @return Decoded int
    // function decode_sint32(uint64 p, bytes memory buf)
    //     internal
    //     pure
    //     returns (
    //         bool,
    //         uint64,
    //         int32
    //     )
    // {
    //     (bool success, uint64 pos, uint64 val) = decode_varint(p, buf);
    //     if (!success) {
    //         return (false, pos, 0);
    //     }

    //     // [STRICT]
    //     // Highest 4 bytes must be 0
    //     if (val & 0xFFFFFFFF00000000 != 0) {
    //         return (false, pos, 0);
    //     }

    //     // https://stackoverflow.com/questions/2210923/zig-zag-decoding/2211086#2211086
    //     uint64 zigzag_val = (val >> 1) ^ (-(val & 1));

    //     return (true, pos, int32(uint32(zigzag_val)));
    // }

    // /// @notice Decode varint sint64.
    // /// @param p Position
    // /// @param buf Buffer
    // /// @return Success
    // /// @return New position
    // /// @return Decoded int
    // function decode_sint64(uint64 p, bytes memory buf)
    //     internal
    //     pure
    //     returns (
    //         bool,
    //         uint64,
    //         int64
    //     )
    // {
    //     (bool success, uint64 pos, uint64 val) = decode_varint(p, buf);
    //     if (!success) {
    //         return (false, pos, 0);
    //     }

    //     // https://stackoverflow.com/questions/2210923/zig-zag-decoding/2211086#2211086
    //     uint64 zigzag_val = (val >> 1) ^ (-(val & 1));

    //     return (true, pos, int64(zigzag_val));
    // }

    /// @notice Decode Boolean.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded bool
    function decode_bool(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            bool
        )
    {
        (bool success, uint64 pos, uint64 val) = decode_varint(p, buf);
        if (!success) {
            return (false, pos, false);
        }

        // [STRICT]
        // Value must be 0 or 1
        if (val > 1) {
            return (false, pos, false);
        }

        if (val == 0) {
            return (true, pos, false);
        }

        return (true, pos, true);
    }

    /// @notice Decode enumeration.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded enum as raw int
    function decode_enum(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            int32
        )
    {
        return decode_int32(p, buf);
    }

    /// @notice Decode fixed 64-bit int.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_bits64(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint64
        )
    {
        uint64 val;

        // Check that index is within bounds
        if (8 + p > buf.length) {
            return (false, p, 0);
        }

        for (uint64 i = 0; i < 8; i++) {
            uint8 b = uint8(buf[p + i]);

            // Little endian
            val |= uint64(b) << uint64(i * 8);
        }

        return (true, p + 8, val);
    }

    /// @notice Decode fixed uint64.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_fixed64(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint64
        )
    {
        (bool success, uint64 pos, uint64 val) = decode_bits64(p, buf);
        if (!success) {
            return (false, pos, 0);
        }

        return (true, pos, val);
    }

    /// @notice Decode fixed int64.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_sfixed64(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            int64
        )
    {
        (bool success, uint64 pos, uint64 val) = decode_bits64(p, buf);
        if (!success) {
            return (false, pos, 0);
        }

        return (true, pos, int64(val));
    }

    /// @notice Decode fixed 32-bit int.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_bits32(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint32
        )
    {
        uint32 val;

        // Check that index is within bounds
        if (4 + p > buf.length) {
            return (false, p, 0);
        }

        for (uint64 i = 0; i < 4; i++) {
            uint8 b = uint8(buf[p + i]);

            // Little endian
            val |= uint32(b) << uint32(i * 8);
        }

        return (true, p + 4, val);
    }

    /// @notice Decode fixed uint32.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_fixed32(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint32
        )
    {
        (bool success, uint64 pos, uint32 val) = decode_bits32(p, buf);
        if (!success) {
            return (false, pos, 0);
        }

        return (true, pos, val);
    }

    /// @notice Decode fixed int32.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Decoded int
    function decode_sfixed32(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            int32
        )
    {
        (bool success, uint64 pos, uint32 val) = decode_bits32(p, buf);
        if (!success) {
            return (false, pos, 0);
        }

        return (true, pos, int32(val));
    }

    /// @notice Decode length-delimited field.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position (after size)
    /// @return Size in bytes
    function decode_length_delimited(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint64
        )
    {
        // Length-delimited fields begin with a varint of the number of bytes that follow
        (bool success, uint64 pos, uint64 size) = decode_varint(p, buf);
        if (!success) {
            return (false, pos, 0);
        }

        // Check for overflow
        if (pos + size < pos) {
            return (false, pos, 0);
        }

        // Check that index is within bounds
        if (size + pos > buf.length) {
            return (false, pos, 0);
        }

        return (true, pos, size);
    }

    /// @notice Decode string.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position
    /// @return Size in bytes
    function decode_string(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            string memory
        )
    {
        (bool success, uint64 pos, uint64 size) =
            decode_length_delimited(p, buf);
        if (!success) {
            return (false, pos, "");
        }

        bytes memory field = new bytes(size);
        for (uint64 i = 0; i < size; i++) {
            field[i] = buf[pos + i];
        }

        return (true, pos + size, string(field));
    }

    /// @notice Decode bytes array.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position (after size)
    /// @return Size in bytes
    function decode_bytes(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint64
        )
    {
        return decode_length_delimited(p, buf);
    }

    /// @notice Decode embedded message.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position (after size)
    /// @return Size in bytes
    function decode_embedded_message(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint64
        )
    {
        return decode_length_delimited(p, buf);
    }

    /// @notice Decode packed repeated field.
    /// @param p Position
    /// @param buf Buffer
    /// @return Success
    /// @return New position (after size)
    /// @return Size in bytes
    function decode_packed_repeated(uint64 p, bytes memory buf)
        internal
        pure
        returns (
            bool,
            uint64,
            uint64
        )
    {
        return decode_length_delimited(p, buf);
    }

    ////////////////////////////////////
    // Encoding
    ////////////////////////////////////

    /// @notice Encode key.
    /// @dev https://developers.google.com/protocol-buffers/docs/encoding#structure
    /// @param field_number Field number
    /// @param wire_type Wire type
    /// @return Marshaled bytes
    function encode_key(uint64 field_number, uint64 wire_type)
        internal
        pure
        returns (bytes memory)
    {
        uint64 key = (field_number << 3) | wire_type;

        bytes memory buf = encode_varint(key);

        return buf;
    }

    /// @notice Encode varint.
    /// @dev https://developers.google.com/protocol-buffers/docs/encoding#varints
    /// @param n Number
    /// @return Marshaled bytes
    function encode_varint(uint64 n) internal pure returns (bytes memory) {
        // Count the number of groups of 7 bits
        // We need this pre-processing step since Solidity doesn't allow dynamic memory resizing
        uint64 tmp = n;
        uint64 num_bytes = 1;
        while (tmp > 0x7F) {
            tmp = tmp >> 7;
            num_bytes += 1;
        }

        bytes memory buf = new bytes(num_bytes);

        tmp = n;
        for (uint64 i = 0; i < num_bytes; i++) {
            // Set the first bit in the byte for each group of 7 bits
            buf[i] = bytes1(0x80 | uint8(tmp & 0x7F));
            tmp = tmp >> 7;
        }
        // Unset the first bit of the last byte
        buf[num_bytes - 1] &= 0x7F;

        return buf;
    }

    /// @notice Encode varint int32.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_int32(int32 n) internal pure returns (bytes memory) {
        return encode_varint(uint64(uint32(n)));
    }

    /// @notice Decode varint int64.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_int64(int64 n) internal pure returns (bytes memory) {
        return encode_varint(uint64(n));
    }

    /// @notice Encode varint uint32.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_uint32(uint32 n) internal pure returns (bytes memory) {
        return encode_varint(n);
    }

    /// @notice Encode varint uint64.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_uint64(uint64 n) internal pure returns (bytes memory) {
        return encode_varint(n);
    }

    /// @notice Encode varint sint32.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_sint32(int32 n) internal pure returns (bytes memory) {
        // https://developers.google.com/protocol-buffers/docs/encoding#signed_integers
        uint32 mask = 0;
        if (n < 0) {
            mask -= 1;
        }
        uint32 zigzag_val = (uint32(n) << 1) ^ mask;

        return encode_varint(zigzag_val);
    }

    /// @notice Encode varint sint64.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_sint64(int64 n) internal pure returns (bytes memory) {
        // https://developers.google.com/protocol-buffers/docs/encoding#signed_integers
        uint64 mask = 0;
        if (n < 0) {
            mask -= 1;
        }
        uint64 zigzag_val = (uint64(n) << 1) ^ mask;

        return encode_varint(zigzag_val);
    }

    /// @notice Encode Boolean.
    /// @param b Boolean
    /// @return Marshaled bytes
    function encode_bool(bool b) internal pure returns (bytes memory) {
        uint64 n = b ? 1 : 0;

        return encode_varint(n);
    }

    /// @notice Encode enumeration.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_enum(int32 n) internal pure returns (bytes memory) {
        return encode_int32(n);
    }

    /// @notice Encode fixed 64-bit int.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_bits64(uint64 n) internal pure returns (bytes memory) {
        bytes memory buf = new bytes(8);

        uint64 tmp = n;
        for (uint64 i = 0; i < 8; i++) {
            // Little endian
            buf[i] = bytes1(uint8(tmp & 0xFF));
            tmp = tmp >> 8;
        }

        return buf;
    }

    /// @notice Encode fixed uint64.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_fixed64(uint64 n) internal pure returns (bytes memory) {
        return encode_bits64(n);
    }

    /// @notice Encode fixed int64.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_sfixed64(int64 n) internal pure returns (bytes memory) {
        return encode_bits64(uint64(n));
    }

    /// @notice Decode fixed 32-bit int.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_bits32(uint32 n) internal pure returns (bytes memory) {
        bytes memory buf = new bytes(4);

        uint64 tmp = n;
        for (uint64 i = 0; i < 4; i++) {
            // Little endian
            buf[i] = bytes1(uint8(tmp & 0xFF));
            tmp = tmp >> 8;
        }

        return buf;
    }

    /// @notice Encode fixed uint32.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_fixed32(uint32 n) internal pure returns (bytes memory) {
        return encode_bits32(n);
    }

    /// @notice Encode fixed int32.
    /// @param n Number
    /// @return Marshaled bytes
    function encode_sfixed32(int32 n) internal pure returns (bytes memory) {
        return encode_bits32(uint32(n));
    }

    /// @notice Encode length-delimited field.
    /// @param b Bytes
    /// @return Marshaled bytes
    function encode_length_delimited(bytes memory b)
        internal
        pure
        returns (bytes memory)
    {
        // Length-delimited fields begin with a varint of the number of bytes that follow
        bytes memory length_buf = encode_uint64(uint64(b.length));
        bytes memory buf = new bytes(b.length + length_buf.length);

        for (uint64 i = 0; i < length_buf.length; i++) {
            buf[i] = length_buf[i];
        }

        for (uint64 i = 0; i < b.length; i++) {
            buf[i + length_buf.length] = b[i];
        }

        return buf;
    }

    /// @notice Encode string.
    /// @param s String
    /// @return Marshaled bytes
    function encode_string(string memory s)
        internal
        pure
        returns (bytes memory)
    {
        return encode_length_delimited(bytes(s));
    }

    /// @notice Encode bytes array.
    /// @param b Bytes
    /// @return Marshaled bytes
    function encode_bytes(bytes memory b) internal pure returns (bytes memory) {
        return encode_length_delimited(b);
    }

    /// @notice Encode embedded message.
    /// @param m Message
    /// @return Marshaled bytes
    function encode_embedded_message(bytes memory m)
        internal
        pure
        returns (bytes memory)
    {
        return encode_length_delimited(m);
    }

    /// @notice Encode packed repeated field.
    /// @param b Bytes
    /// @return Marshaled bytes
    function encode_packed_repeated(bytes memory b)
        internal
        pure
        returns (bytes memory)
    {
        return encode_length_delimited(b);
    }
}

contracts/forking/SimpleSchelling.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.3;

import {IBridgeProxy} from "../interfaces/IBridgeProxy.sol";

/**
 @author Tellor Inc.
 @title SimpleSchelling
 @dev This contract provides a simple Schelling game for pausing and updating a Tellor Layer
 * Light Client Bridge contract in the event that Tellor Layer chain is attacked. Any user can pay
 * a high fee to begin the Schelling game. Then either the bridge is immediately paused or an optional 
 * second signature is required from a configured guardian address. The initiator has a period of time to
 * propose a new implementation address. Then anyone can pay to support or oppose the proposal. Once the voting
 * period expires, the bridge is unpaused, and if the proposal is supported by a majority of the tokens, the bridge 
 * implementation address is updated. The winning side gets their tokens refunded and splits the losing side's tokens.
*/
contract SimpleSchelling {
    // Storage
    IBridgeProxy public bridgeProxy; // bridge proxy contract
    uint256 public minInitAmount; // minimum amount of tokens required to initiate Schelling game. 10% is burned
    uint256 public proposalCount; // number of proposals
    uint256 public submissionPeriod; // period after pausing bridge to submit implementation
    uint256 public extensionPeriod; // amount of time added to expiration time when outcome changes
    address public guardian; // optional guardian to sign proposal to pause bridge
    bool public requireGuardianSignature; // whether or not guardian signature is required to pause bridge

    mapping(uint256 => ForkProposal) public proposals;

    // Structs
    struct ForkProposal {
        address initiator; // address of user who initiated Schelling game
        address proposedImplementation; // address of proposed bridge implementation
        uint256 amountFor; // amount of tokens in support of proposal
        uint256 amountAgainst; // amount of tokens against proposal
        uint256 submissionDeadline; // deadline for submitting implementation address
        uint256 expirationTime; // deadline for voting, extended when outcome changes
        bool executed; // whether or not proposal has been executed
        bool guardianSigned; // whether or not guardian has signed proposal
        ProposalOutcome outcome; // final outcome of proposal
        mapping(address => Vote) votesFor; // mapping of addresses to votes in support of proposal
        mapping(address => Vote) votesAgainst; // mapping of addresses to votes against proposal
    }

    struct Vote {
        uint256 amount;
    }

    enum ProposalOutcome {
        INVALID,
        FOR,
        AGAINST
    }

    // Functions
    /**
     * @dev Initializes system parameters
     * @param _bridgeProxy address of bridge proxy contract
     * @param _minInitAmount minimum amount of tokens required to initiate Schelling game. 10% is burned
     * @param _submissionPeriod maximum period after pausing bridge to submit implementation
     * @param _extensionPeriod total voting period, reset when outcome changes
     * @param _requireGuardianSignature whether or not guardian signature is required to pause bridge
     * @param _guardian optional guardian to sign proposal to pause bridge
     */
    constructor(
        address _bridgeProxy,
        uint256 _minInitAmount,
        uint256 _submissionPeriod,
        uint256 _extensionPeriod,
        bool _requireGuardianSignature,
        address _guardian
    ) {
        bridgeProxy = IBridgeProxy(_bridgeProxy);
        minInitAmount = _minInitAmount;
        submissionPeriod = _submissionPeriod;
        extensionPeriod = _extensionPeriod;
        requireGuardianSignature = _requireGuardianSignature;
        guardian = _guardian;
    }

    /**
     * @dev Claim tokens after proposal has been executed
     * @param _proposalId ID of proposal to claim tokens from
     */
    function claim(uint256 _proposalId) external {
        ForkProposal storage _proposal = proposals[_proposalId];
        require(_proposal.executed, "not executed");

        uint256 _payoutAmount;
        if (_proposal.outcome == ProposalOutcome.INVALID) {
            _payoutAmount =
                _proposal.votesFor[msg.sender].amount +
                _proposal.votesAgainst[msg.sender].amount;
            _proposal.votesFor[msg.sender].amount = 0;
            _proposal.votesAgainst[msg.sender].amount = 0;
        } else if (_proposal.outcome == ProposalOutcome.FOR) {
            _payoutAmount =
                (_proposal.votesFor[msg.sender].amount *
                    _proposal.amountAgainst) /
                _proposal.amountFor +
                _proposal.votesFor[msg.sender].amount;
            _proposal.votesFor[msg.sender].amount = 0;
        } else {
            _payoutAmount =
                (_proposal.votesAgainst[msg.sender].amount *
                    _proposal.amountFor) /
                _proposal.amountAgainst +
                _proposal.votesAgainst[msg.sender].amount;
            _proposal.votesAgainst[msg.sender].amount = 0;
        }
        require(_payoutAmount > 0, "no vote");
        payable(msg.sender).transfer(_payoutAmount);
    }

    /**
     * @dev Execute proposal after voting period has expired
     * or after submission period has expired if guardian required but never signed
     * @param _proposalId ID of proposal to execute
     */
    function executeProposal(uint256 _proposalId) external {
        ForkProposal storage _proposal = proposals[_proposalId];
        require(
            _proposal.submissionDeadline < block.timestamp,
            "submission period not expired"
        );
        require(!_proposal.executed, "already executed");
        if (
            (requireGuardianSignature && _proposal.guardianSigned) ||
            !requireGuardianSignature
        ) {
            require(
                _proposal.expirationTime < block.timestamp,
                "proposal not expired"
            );
            if (
                _proposal.amountFor > _proposal.amountAgainst &&
                _proposal.proposedImplementation != address(0)
            ) {
                // if more tokens in support AND implementation submitted, update implementation
                bridgeProxy.updateImplementation(
                    _proposal.proposedImplementation
                );
                _proposal.outcome = ProposalOutcome.FOR;
            } else {
                _proposal.outcome = ProposalOutcome.AGAINST;
            }
            bridgeProxy.unpauseBridge();
        } else {
            // if guardian signature required and not signed, proposal is invalid
            _proposal.outcome = ProposalOutcome.INVALID;
        }
        _proposal.executed = true;
    }

    /**
     * @dev Guardian can sign proposal and pause bridge, only if required
     * @param _proposalId ID of proposal
     */
    function guardianPauseBridge(uint256 _proposalId) external {
        require(msg.sender == guardian, "not guardian");
        require(requireGuardianSignature, "guardian signature not required");
        require(!bridgeProxy.paused(), "bridge already paused");
        ForkProposal storage _proposal = proposals[_proposalId];
        require(
            _proposal.submissionDeadline > block.timestamp,
            "submission period expired"
        );
        _proposal.guardianSigned = true;
        bridgeProxy.pauseBridge();
    }

    /**
     * @dev Initiates Schelling game by paying minimum amount of tokens
     * @notice 10% of amount is burned
     */
    function initiateProposal() external payable {
        require(msg.value >= minInitAmount, "insufficient amount");
        require(!bridgeProxy.paused(), "bridge already paused");
        ForkProposal storage _proposal = proposals[proposalCount];
        uint256 _burnAmount = minInitAmount / 10;
        _proposal.initiator = msg.sender;
        _proposal.amountFor = msg.value - _burnAmount;
        _proposal.submissionDeadline = block.timestamp + submissionPeriod;
        _proposal.expirationTime =
            block.timestamp +
            extensionPeriod +
            submissionPeriod;
        _proposal.votesFor[msg.sender].amount += msg.value - _burnAmount;
        proposalCount++;
        payable(address(0)).transfer(_burnAmount);
        if (!requireGuardianSignature) {
            bridgeProxy.pauseBridge();
        }
    }

    /**
     * @dev Propose new implementation address after Schelling game initiated
     * @param _proposalId ID of proposal
     * @param _proposedImplementation address of proposed implementation
     */
    function submitImplementation(
        uint256 _proposalId,
        address _proposedImplementation
    ) external {
        ForkProposal storage _proposal = proposals[_proposalId];
        require(_proposal.initiator == msg.sender, "not initiator");
        require(_proposal.proposedImplementation == address(0), "already set");
        require(
            _proposal.submissionDeadline > block.timestamp,
            "proposal expired"
        );
        _proposal.proposedImplementation = _proposedImplementation;
    }

    /**
     * @dev Guardian can remove requirement for signature to pause bridge
     */
    function throwAwayGuardianship() external {
        require(msg.sender == guardian, "not guardian");
        guardian = address(0);
        requireGuardianSignature = false;
    }

    /**
     * @dev Transfer guardianship to new address
     * @param _newGuardian address of new guardian
     */
    function transferGuardianship(address _newGuardian) external {
        require(msg.sender == guardian, "not guardian");
        guardian = _newGuardian;
    }

    /**
     * @dev Allows a voter to change their vote before expiration
     * @notice Initiator cannot update vote, and 10% of amount is burned
     * @param _proposalId ID of proposal
     * @param _for whether or not to vote in support of proposal
     */
    function updateVote(uint256 _proposalId, bool _for) external {
        ForkProposal storage _proposal = proposals[_proposalId];
        require(
            msg.sender != _proposal.initiator,
            "initiator cannot update vote"
        );
        require(_proposal.expirationTime > block.timestamp, "proposal expired");
        uint256 _amount;
        // burn 10% so that griefing by flip flopping is expensive
        uint256 _burnAmount;
        // get current outcome before vote
        bool _forInLead = _proposal.amountFor > _proposal.amountAgainst;
        if (_for) {
            _burnAmount = _proposal.votesAgainst[msg.sender].amount / 10;
            _amount = _proposal.votesAgainst[msg.sender].amount - _burnAmount;
            _proposal.amountFor += _amount;
            _proposal.votesFor[msg.sender].amount += _amount;
            _proposal.amountAgainst -= _amount;
            _proposal.votesAgainst[msg.sender].amount = 0;
        } else {
            _burnAmount = _proposal.votesFor[msg.sender].amount / 10;
            _amount = _proposal.votesFor[msg.sender].amount - _burnAmount;
            _proposal.amountAgainst += _amount;
            _proposal.votesAgainst[msg.sender].amount += _amount;
            _proposal.amountFor -= _amount;
            _proposal.votesFor[msg.sender].amount = 0;
        }
        require(_amount > 0, "no vote");
        // if outcome changed and past submission deadline, reset expiration time
        if (
            _forInLead &&
            _proposal.amountAgainst >= _proposal.amountFor &&
            _proposal.submissionDeadline < block.timestamp
        ) {
            _proposal.expirationTime = block.timestamp + extensionPeriod;
        } else if (
            !_forInLead &&
            _proposal.amountFor > _proposal.amountAgainst &&
            _proposal.submissionDeadline < block.timestamp
        ) {
            _proposal.expirationTime = block.timestamp + extensionPeriod;
        }
        payable(address(0)).transfer(_burnAmount);
    }

    /**
     * @dev Vote in support of or against proposal
     * @param _proposalId ID of proposal
     * @param _for whether or not to vote in support of proposal
     */
    function vote(uint256 _proposalId, bool _for) external payable {
        require(msg.value > 0, "insufficient amount");
        ForkProposal storage _proposal = proposals[_proposalId];
        require(_proposal.expirationTime > block.timestamp, "proposal expired");
        // get current outcome before vote
        bool _forInLead = _proposal.amountFor > _proposal.amountAgainst;
        if (_for) {
            _proposal.amountFor += msg.value;
            _proposal.votesFor[msg.sender].amount += msg.value;
        } else {
            _proposal.amountAgainst += msg.value;
            _proposal.votesAgainst[msg.sender].amount += msg.value;
        }
        // if outcome changed and past submission deadline, reset expiration time
        if (
            _forInLead &&
            _proposal.amountAgainst >= _proposal.amountFor &&
            _proposal.submissionDeadline < block.timestamp
        ) {
            _proposal.expirationTime = block.timestamp + extensionPeriod;
        } else if (
            !_forInLead &&
            _proposal.amountFor > _proposal.amountAgainst &&
            _proposal.submissionDeadline < block.timestamp
        ) {
            _proposal.expirationTime = block.timestamp + extensionPeriod;
        }
    }

    // *****************************************************************************
    // *                                                                           *
    // *                               Getters                                     *
    // *                                                                           *
    // *****************************************************************************

    /**
     * @dev Get proposal details
     * @param _proposalId ID of proposal
     * @return initiator address of user who initiated Schelling game
     * @return proposedImplementation address of proposed bridge implementation
     * @return amountFor amount of tokens in support of proposal
     * @return amountAgainst amount of tokens against proposal
     * @return submissionDeadline deadline for submitting implementation address
     * @return expirationTime deadline for voting, extended when outcome changes
     * @return executed whether or not proposal has been executed
     * @return guardianSigned whether or not guardian has signed proposal
     * @return outcome final outcome of proposal
     */
    function getProposal(
        uint256 _proposalId
    )
        public
        view
        returns (
            address,
            address,
            uint256,
            uint256,
            uint256,
            uint256,
            bool,
            bool,
            ProposalOutcome
        )
    {
        ForkProposal storage _proposal = proposals[_proposalId];
        return (
            _proposal.initiator,
            _proposal.proposedImplementation,
            _proposal.amountFor,
            _proposal.amountAgainst,
            _proposal.submissionDeadline,
            _proposal.expirationTime,
            _proposal.executed,
            _proposal.guardianSigned,
            _proposal.outcome
        );
    }

    /**
     * @dev Get vote details
     * @param _proposalId ID of proposal
     * @param _voter address of voter
     * @return amountFor amount of tokens in support of proposal
     * @return amountAgainst amount of tokens against proposal
     */
    function getVotes(
        uint256 _proposalId,
        address _voter
    ) public view returns (uint256, uint256) {
        ForkProposal storage _proposal = proposals[_proposalId];
        return (
            _proposal.votesFor[_voter].amount,
            _proposal.votesAgainst[_voter].amount
        );
    }
}

